export const 入山符丙三 = (bi) => {
    const u = bi.u;
    const k = 1.05;
    const X = (c) => (c - 12.3) * k;
    const Z = (r) => (r - 0.9) * k;
    const 線 = (書, 寬 = 0.55) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.55) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 星 = (c, r, 半 = 0.55) => bi.dot(X(c), Z(r), 半);
    // 頂桁綴珠
    線(p => p.M(X(8.3), Z(1.7)).L(X(16.9), Z(1.5)), 0.6);
    星(17.3, 1.5, 0.6);
    // 星桿三
    星(8.2, 5.1);
    線(p => p.M(X(8.2), Z(5.6)).L(X(8.2), Z(7.9)), 0.5);
    星(8.2, 8.5);
    星(12.5, 4.9);
    線(p => p.M(X(12.3), Z(5.4)).L(X(11.4), Z(7.6)), 0.5);
    星(11.2, 8.1);
    線(p => p.M(X(12.7), Z(5.4)).L(X(13.4), Z(7.5)), 0.5);
    星(13.6, 8.0);
    星(15.6, 5.2);
    線(p => p.M(X(15.6), Z(5.7)).L(X(15.6), Z(7.9)), 0.5);
    星(15.6, 8.4);
    // 括箱（桁列夾雙括）
    const 箱 = (x0, x1, 桁) => {
        for (const z of 桁)
            線(p => p.M(X(x0), Z(z)).L(X(x1), Z(z - 0.2)), 0.55);
        出(p => p.M(X(x0), Z(桁[0] + 0.3)).C(X(x0 - 0.45), Z((桁[0] + 桁[桁.length - 1]) / 2), X(x0 - 0.35), Z(桁[桁.length - 1] - 0.4), X(x0 + 0.1), Z(桁[桁.length - 1] + 0.2)), 0.5);
        出(p => p.M(X(x1), Z(桁[0] + 0.1)).C(X(x1 + 0.45), Z((桁[0] + 桁[桁.length - 1]) / 2), X(x1 + 0.35), Z(桁[桁.length - 1] - 0.5), X(x1 - 0.1), Z(桁[桁.length - 1])), 0.5);
    };
    // 左列三箱
    箱(6.4, 10.5, [10.4, 11.4, 12.4]);
    for (const z of [13.4, 14.3, 15.1])
        線(p => p.M(X(6.9), Z(z)).C(X(8.2), Z(z + 0.25), X(9.8), Z(z + 0.1), X(10.9), Z(z - 0.2)), 0.5);
    線(p => p.M(X(8.5), Z(14.6)).L(X(8.5), Z(15.6)), 0.45);
    箱(6.3, 11.2, [16.5, 17.5, 18.4, 19.3]);
    // 中脊長豎
    線(p => p.M(X(12.1), Z(9.5)).L(X(12.05), Z(19.5)), 0.6);
    // 右列二箱
    箱(12.9, 16.9, [10.2, 11.2, 12.2]);
    箱(12.9, 17.5, [14.5, 15.5, 16.4, 17.3]);
    // 中桁
    線(p => p.M(X(6.6), Z(20.3)).L(X(16.2), Z(20.0)), 0.62);
    // 門式底段：左箱桁
    出(p => p.M(X(7.5), Z(22.5)).C(X(6.9), Z(25.5), X(6.8), Z(28.3), X(6.3), Z(30.8)), 0.6);
    for (const z of [23.2, 24.4, 27.0, 28.2])
        線(p => p.M(X(7.6), Z(z)).L(X(12.2), Z(z - 0.2)), 0.55);
    // 中蓮節鏈（葉眼二疊）
    const 眼 = (z0, z1, 幅) => {
        線(p => p.M(X(13.1), Z(z0)).C(X(13.1 - 幅), Z((z0 + z1) / 2), X(13.1 - 幅 * 0.6), Z(z1 - 0.2), X(13.1), Z(z1)), 0.5);
        線(p => p.M(X(13.1), Z(z0)).C(X(13.1 + 幅), Z((z0 + z1) / 2), X(13.1 + 幅 * 0.6), Z(z1 - 0.2), X(13.1), Z(z1)), 0.5);
    };
    眼(22.7, 25.4, 0.8);
    眼(25.6, 28.8, 0.75);
    // 右箱桁
    for (const z of [23.4, 24.6, 26.0, 27.3])
        線(p => p.M(X(14.2), Z(z)).L(X(17.6), Z(z - 0.15)), 0.55);
    出(p => p.M(X(17.7), Z(23.0)).C(X(18.1), Z(24.6), X(18.1), Z(26.2), X(17.8), Z(27.7)), 0.5);
    // 右垂長曳重墨收
    星(18.2, 21.6, 0.5);
    出(p => p.M(X(18.0), Z(17.6)).C(X(18.3), Z(21.5), X(18.2), Z(25.5), X(18.8), Z(28.5))
        .C(X(19.1), Z(29.8), X(19.2), Z(30.6), X(19.0), Z(31.2)), 0.7);
    bi.dot(X(18.95), Z(30.3), 0.75);
};
